import{_ as t,o,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"11. Disputes Settling Procedures","description":"","frontmatter":{"title":"11. Disputes Settling Procedures","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","parental-leave","disputes","union-matters"]},"headers":[],"relativePath":"ebas/mspp/disputes/11-disputes-settling-procedures.md","filePath":"ebas/mspp/disputes/11-disputes-settling-procedures.md"}'),r={name:"ebas/mspp/disputes/11-disputes-settling-procedures.md"};function n(a,e,p,l,h,d){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_11-disputes-settling-procedures" tabindex="-1">11. Disputes Settling Procedures <a class="header-anchor" href="#_11-disputes-settling-procedures" aria-label="Permalink to &quot;11. Disputes Settling Procedures&quot;">​</a></h1><p><strong>11.1</strong> Resolution of disputes and grievances</p><p><strong>a.</strong> For the purpose of this clause 11, a dispute includes a grievance.</p><p><strong>b.</strong> This dispute resolution procedure will apply to any dispute arising in relation to:</p><p><strong>(i)</strong> this Agreement (including but not limited to a request for flexible working arrangements) or</p><p><strong>(ii)</strong> a request for an additional 12 months parental leave;</p><p><strong>(iii)</strong> the NES.</p><p><strong>c.</strong> A party to the dispute may choose to be represented at any stage by a representative including a Union or employer organisation. A representative, including a Union or employer organisation on behalf of an Employer, may initiate a dispute.</p><p><strong>11.2</strong> Obligations</p><p><strong>a.</strong> The parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in this clause and must cooperate to ensure that these processes are carried out expeditiously.</p><p><strong>b.</strong> While the dispute resolution procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>c.</strong> This requirement does not apply where an Employee:</p><p><strong>(i)</strong> has a reasonable concern about an imminent risk to his or her health or safety;</p><p><strong>(ii)</strong> has advised the Employer of the concern; and</p><p><strong>(iii)</strong> has not unreasonably failed to comply with a direction by the Employer to perform other available work that is safe and appropriate for the Employee to perform.</p><p><strong>d.</strong> No party to a dispute or person covered by the Agreement will be prejudiced with respect to the resolution of the dispute by continuing work under this clause.</p><p><strong>11.3</strong> Dispute settlement facilitation</p><p><strong>a.</strong> Where the chosen representative is another Employee of the Employer, that Employee will be released by the Employer from normal duties as is reasonably necessary to enable them to represent the Employee/s including:</p><p><strong>(i)</strong> investigating the circumstances of the dispute; and</p><p><strong>(ii)</strong> participating in the processes to resolve the dispute, including conciliation and arbitration.</p><p><strong>b.</strong> An Employee who is party to the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>11.4</strong> Discussion of dispute at workplace level</p><p><strong>a.</strong> The parties will attempt to resolve the dispute at the workplace level as follows:</p><p><strong>(i)</strong> in the first instance by discussions between the Employee/s (and/or representative) and the Employees’ manager/supervisor or other relevant manager; and</p><p><strong>(ii)</strong> where the dispute or grievance is about the conduct of the employee(s)’ manager/supervisor, the employee(s) may first discuss the matter with another representative of the Employer; and</p><p><strong>(iii)</strong> if the dispute is still unresolved, by discussions between the Employee/s (and/or representative) and more senior managers.</p><p><strong>b.</strong> Nothing in this clause 11.4 prevents the Parties from agreeing, at any time, to conducting their discussions in writing, subject to 11.2.</p><p><strong>c.</strong> The discussions at subclause 11.4a will take place within fourteen days or such longer period as mutually agreed, save that agreement will not be unreasonably withheld.</p><p><strong>d.</strong> Where a Party believes the requirements of this clause 11.4 have not been complied with, they will notify the other of their concern in writing as soon as practicable (and preferably before an appearance at the FWC).</p><p><strong>e.</strong> If a dispute cannot be resolved at the workplace it may be referred by a party to the dispute or representative to the Commission for conciliation and, if the matter in dispute remains unresolved, arbitration.</p><p><strong>11.5</strong> Disputes of a collective character Disputes of a collective character may be dealt with more expeditiously by an early reference to the Commission. However, no dispute of a collective character may be referred to the Commission directly without a genuine attempt to resolve the dispute at the workplace level.</p><p><strong>11.6</strong> Conciliation</p><p><strong>a.</strong> Where a dispute is referred for conciliation, the Commission member will do everything the member deems right and proper to assist the parties to settle the dispute.</p><p><strong>b.</strong> Conciliation before the Commission is complete when:</p><p><strong>(i)</strong> the parties to the dispute agree that it is settled; or</p><p><strong>(ii)</strong> the Commission member conducting the conciliation, either on their own motion or after an application by a party, is satisfied there is no likelihood that further conciliation will result in settlement within a reasonable period; or</p><p><strong>(iii)</strong> the parties to the dispute inform the Commission member there is no likelihood the dispute will be settled and the member does not have substantial reason to refuse to regard conciliation as complete.</p><p><strong>11.7</strong> Arbitration</p><p><strong>a.</strong> If, when conciliation is complete, the dispute is not settled, either party may request the Commission proceed to determine the dispute by arbitration.</p><p><strong>b.</strong> The Commission member that conciliated the dispute will not arbitrate the dispute if a party objects to the member doing so.</p><p><strong>c.</strong> Subject to subclause 11.7d below, a decision of the Commission is binding upon the persons covered by this Agreement.</p><p><strong>d.</strong> An appeal lies to a Full Bench of the Commission, with the leave of the Full Bench, against a determination of a single member of the Commission made pursuant to this clause.</p><p><strong>11.8</strong> Conduct of matters before the Commission</p><p><strong>a.</strong> Subject to any agreement between the parties to the dispute in relation to a particular dispute or grievance and the provisions of this clause, in dealing with a dispute or grievance through conciliation or arbitration, the Commission may conduct the matter in accordance with sections 577, 578 and Subdivision B of Division 3 of Part 5-1 of the Act.</p><p><strong>b.</strong> For the avoidance of doubt, nothing in this clause 11 affects the operation of s.596 of the Act.</p><p>Plain language terms: dispute resolution, grievance, FWC dispute.</p>',46)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
